parameters.functionCode:
// Parsear email y extraer datos
const email = items[0].json.message || items[0].json.payload;
const headers = email.payload.headers;

const getName = (key) => headers.find(h => h.name === key)?.value || '';

return {
  json: {
    from_name: getName('From').split('<')[0].trim(),
    from_email: getName('From').match(/<(.+?)>/)?.[1] || '',
    subject: getName('Subject'),
    thread_id: email.threadId,
    message_id: email.id,
    body: email.payload.parts?.[0]?.body?.data ? Buffer.from(email.payload.parts[0].body.data, 'base64').toString('utf-8') : '',
    received_at: new Date(parseInt(email.internalDate)).toISOString()
  }
};

// Validaciones previas a IA
const email = items[0].json.from_email;
const nombre = items[0].json.from_name;
const mensaje = items[0].json.body;

const validations = {
  email_valido: /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email),
  nombre_presente: nombre && nombre.length > 2,
  mensaje_presente: mensaje && mensaje.length > 20
};

return {
  json: {
    ...items[0].json,
    validaciones: validations,
    listo_para_ia: Object.values(validations).every(v => v)
  }
};

