// Parsear respuesta JSON de OpenAI
try {
  const content = items[0].json.message.content;
  const json = JSON.parse(content);

  return {
    json: {
      ...items[0].json,
      ia_result: json,
      parse_success: true
    }
  };
} catch (e) {
  return {
    json: {
      ...items[0].json,
      parse_error: e.message,
      parse_success: false
    }
  };
}

